import React, { useState } from "react";

function SecurityTraining() {
  const [activeModule, setActiveModule] = useState(null);

  const modules = [
    {
      id: 1,
      title: "Password Security",
      description: "Learn how to create and manage secure passwords",
      duration: "15 min",
      level: "Beginner",
      content: [
        "Use at least 12 characters with a mix of letters, numbers, and symbols",
        "Never reuse passwords across different accounts",
        "Use a password manager to store your passwords securely",
        "Enable two-factor authentication whenever possible",
        "Never share your password via email or phone",
      ],
    },
    {
      id: 2,
      title: "Phishing Awareness",
      description: "Recognize and avoid phishing attacks",
      duration: "20 min",
      level: "Intermediate",
      content: [
        "Check sender email addresses carefully for misspellings",
        "Hover over links before clicking to see the actual URL",
        "Be wary of urgent requests for personal information",
        "Verify requests through official channels",
        "Report suspicious emails to your IT security team",
      ],
    },
    {
      id: 3,
      title: "Social Engineering",
      description: "Understanding manipulation tactics used by attackers",
      duration: "25 min",
      level: "Intermediate",
      content: [
        "Be cautious of unsolicited phone calls asking for sensitive info",
        "Verify the identity of people requesting access",
        "Don't let urgency override your security judgment",
        "Follow proper verification procedures",
        "Report suspicious requests to security team",
      ],
    },
    {
      id: 4,
      title: "Data Protection",
      description: "How to handle and protect sensitive data",
      duration: "20 min",
      level: "Advanced",
      content: [
        "Classify data according to sensitivity levels",
        "Encrypt sensitive files before sharing",
        "Use secure file transfer protocols",
        "Follow data retention policies",
        "Properly dispose of sensitive data",
      ],
    },
    {
      id: 5,
      title: "Secure Browsing",
      description: "Best practices for safe internet usage",
      duration: "15 min",
      level: "Beginner",
      content: [
        "Always check for HTTPS in website URLs",
        "Keep your browser and plugins updated",
        "Use ad-blockers and script blockers",
        "Avoid public WiFi for sensitive transactions",
        "Clear browser cache regularly",
      ],
    },
    {
      id: 6,
      title: "Incident Response",
      description: "What to do when a security incident occurs",
      duration: "30 min",
      level: "Advanced",
      content: [
        "Know how to report security incidents",
        "Don't try to fix it yourself - call the experts",
        "Document everything you observe",
        "Preserve evidence for investigation",
        "Follow your organization's incident response plan",
      ],
    },
  ];

  const completedModules = [1, 2]; // Example completed

  return (
    <div className="training-page">
      <div className="page-header">
        <h1>Security Training</h1>
        <p>Complete security awareness training modules</p>
      </div>

      <div className="training-stats">
        <div className="stat-card">
          <div className="stat-icon">📚</div>
          <div className="stat-info">
            <h3>{modules.length}</h3>
            <p>Total Modules</p>
          </div>
        </div>
        <div className="stat-card">
          <div className="stat-icon">✅</div>
          <div className="stat-info">
            <h3>{completedModules.length}</h3>
            <p>Completed</p>
          </div>
        </div>
        <div className="stat-card">
          <div className="stat-icon">⏱️</div>
          <div className="stat-info">
            <h3>125</h3>
            <p>Minutes of Training</p>
          </div>
        </div>
      </div>

      <div className="modules-grid">
        {modules.map((module) => (
          <div
            key={module.id}
            className={`module-card ${completedModules.includes(module.id) ? "completed" : ""}`}
            onClick={() => setActiveModule(activeModule === module.id ? null : module.id)}
          >
            <div className="module-header">
              <div className="module-number">{module.id}</div>
              {completedModules.includes(module.id) && (
                <span className="completed-badge">Completed</span>
              )}
            </div>
            <h3>{module.title}</h3>
            <p>{module.description}</p>
            <div className="module-meta">
              <span className="duration">⏱️ {module.duration}</span>
              <span className={`level level-${module.level.toLowerCase()}`}>
                {module.level}
              </span>
            </div>

            {activeModule === module.id && (
              <div className="module-content">
                <h4>Key Points:</h4>
                <ul>
                  {module.content.map((point, index) => (
                    <li key={index}>{point}</li>
                  ))}
                </ul>
                <button className="btn btn-primary btn-block">
                  Mark as Complete
                </button>
              </div>
            )}
          </div>
        ))}
      </div>

      <style>{`
        .training-page {
          min-height: 100vh;
          background: var(--bg-light);
        }
        .page-header {
          background: var(--secondary-color);
          color: white;
          padding: 30px 40px;
        }
        .page-header h1 {
          font-size: 28px;
          margin-bottom: 8px;
        }
        .page-header p {
          opacity: 0.8;
        }
        .training-stats {
          display: grid;
          grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
          gap: 20px;
          padding: 30px 40px;
        }
        .stat-card {
          background: white;
          padding: 24px;
          border-radius: var(--radius-lg);
          display: flex;
          align-items: center;
          gap: 16px;
          box-shadow: var(--shadow-sm);
        }
        .stat-icon {
          font-size: 32px;
        }
        .stat-info h3 {
          font-size: 24px;
          color: var(--secondary-color);
        }
        .stat-info p {
          font-size: 14px;
          color: var(--text-muted);
        }
        .modules-grid {
          display: grid;
          grid-template-columns: repeat(auto-fit, minmax(350px, 1fr));
          gap: 24px;
          padding: 0 40px 40px;
        }
        .module-card {
          background: white;
          padding: 24px;
          border-radius: var(--radius-lg);
          box-shadow: var(--shadow-sm);
          cursor: pointer;
          transition: all 0.2s;
        }
        .module-card:hover {
          transform: translateY(-3px);
          box-shadow: var(--shadow-md);
        }
        .module-card.completed {
          border-left: 4px solid var(--success-color);
        }
        .module-header {
          display: flex;
          justify-content: space-between;
          align-items: center;
          margin-bottom: 12px;
        }
        .module-number {
          width: 32px;
          height: 32px;
          background: var(--primary-color);
          color: white;
          border-radius: 50%;
          display: flex;
          align-items: center;
          justify-content: center;
          font-weight: 600;
        }
        .completed-badge {
          background: var(--success-color);
          color: white;
          padding: 4px 10px;
          border-radius: 20px;
          font-size: 12px;
          font-weight: 500;
        }
        .module-card h3 {
          font-size: 18px;
          margin-bottom: 8px;
          color: var(--secondary-color);
        }
        .module-card > p {
          color: var(--text-muted);
          font-size: 14px;
          margin-bottom: 15px;
        }
        .module-meta {
          display: flex;
          gap: 12px;
          font-size: 13px;
        }
        .duration {
          color: var(--text-muted);
        }
        .level {
          padding: 2px 8px;
          border-radius: 4px;
          font-weight: 500;
        }
        .level-beginner {
          background: #d1fae5;
          color: #059669;
        }
        .level-intermediate {
          background: #fef3c7;
          color: #d97706;
        }
        .level-advanced {
          background: #fee2e2;
          color: #dc2626;
        }
        .module-content {
          margin-top: 20px;
          padding-top: 20px;
          border-top: 1px solid var(--border-color);
        }
        .module-content h4 {
          font-size: 14px;
          margin-bottom: 12px;
          color: var(--secondary-color);
        }
        .module-content ul {
          list-style: none;
          margin-bottom: 20px;
        }
        .module-content li {
          padding: 8px 0;
          font-size: 14px;
          color: var(--text-muted);
          position: relative;
          padding-left: 20px;
        }
        .module-content li::before {
          content: "•";
          position: absolute;
          left: 0;
          color: var(--primary-color);
        }
        @media (max-width: 768px) {
          .training-stats, .modules-grid {
            padding-left: 20px;
            padding-right: 20px;
          }
        }
      `}</style>
    </div>
  );
}

export default SecurityTraining;
